"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { LocalDB } from "@/lib/local-storage/db"
import { computeScoreForSecurity } from "@/lib/analysis/scoring"

interface Opportunity {
  id: string
  symbol: string
  name: string
  score: number
}

export function OpportunityPanel() {
  const [opps, setOpps] = useState<Opportunity[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let mounted = true
    const load = async () => {
      setLoading(true)
      try {
        const secs = await LocalDB.getSecurities()

        // use a simple sessionStorage cache keyed by date to avoid recalculating too often
        const cacheKey = "opportunity_scores"
        const cachedRaw = sessionStorage.getItem(cacheKey)
        let cache: Record<string, { score: number; ts: number }> = {}
        if (cachedRaw) {
          try {
            cache = JSON.parse(cachedRaw)
          } catch (e) {
            cache = {}
          }
        }

        const enriched = await Promise.all(
          secs.map(async (s) => {
            const cacheEntry = cache[s.id]
            const now = Date.now()
            // use cached score if it's younger than 30s
            if (cacheEntry && now - cacheEntry.ts < 30 * 1000) {
              return { id: s.id, symbol: s.symbol, name: s.name, score: cacheEntry.score }
            }

            const score = await computeScoreForSecurity(s as any)
            cache[s.id] = { score, ts: now }
            return { id: s.id, symbol: s.symbol, name: s.name, score }
          }),
        )

        // persist updated cache
        try {
          sessionStorage.setItem(cacheKey, JSON.stringify(cache))
        } catch (e) {
          // ignore storage errors
        }

        if (!mounted) return
        const top = enriched
          .sort((a, b) => b.score - a.score)
          .slice(0, 5)
          .map((e) => ({ id: e.id, symbol: e.symbol, name: e.name, score: Math.round(e.score * 100) / 100 }))

        setOpps(top)
      } catch (err) {
        console.error(err)
      } finally {
        if (mounted) setLoading(false)
      }
    }

    load()

    return () => {
      mounted = false
    }
  }, [])

  return (
    <Card>
      <CardHeader>
        <CardTitle>Top Opportunities</CardTitle>
      </CardHeader>
      <CardContent>
        {loading && <div className="text-sm text-gray-500">Scanning market...</div>}

        {!loading && opps.length === 0 && <div className="text-sm text-gray-500">No opportunities found.</div>}

        <ul className="space-y-2">
          {opps.map((o) => (
            <li key={o.id} className="flex items-center justify-between">
              <div>
                <div className="font-semibold">{o.symbol}</div>
                <div className="text-xs text-gray-500">{o.name}</div>
              </div>
              <div className="text-sm font-medium text-right">
                <div className="text-blue-600">{o.score.toFixed(2)}</div>
              </div>
            </li>
          ))}
        </ul>
      </CardContent>
    </Card>
  )
}
