"use client"

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts"
import Link from "next/link"
import { TrendingUp } from "lucide-react"

interface Fund {
  id: string
  fund_name: string
  fund_code: string
  fund_type: string
  nav: number
  aum: number
  risk_level: string
}

interface FundPerformanceProps {
  managedFunds: Fund[]
}

export function FundPerformance({ managedFunds }: FundPerformanceProps) {
  const formatCurrency = (value: number) => {
    const crores = value / 10000000
    return `₹${crores.toFixed(2)} Cr`
  }

  // Mock performance data for chart
  const performanceData = [
    { month: "Jan", value: 98 },
    { month: "Feb", value: 102 },
    { month: "Mar", value: 105 },
    { month: "Apr", value: 108 },
    { month: "May", value: 112 },
    { month: "Jun", value: 115 },
  ]

  return (
    <Card>
      <CardHeader>
        <CardTitle>Fund Performance</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="mb-6">
          <ResponsiveContainer width="100%" height={250}>
            <LineChart data={performanceData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="month" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={2} name="Portfolio Index" />
            </LineChart>
          </ResponsiveContainer>
        </div>

        <div className="space-y-3">
          {managedFunds.map((fund) => (
            <div key={fund.id} className="flex items-center justify-between rounded-lg border p-4">
              <div className="flex-1">
                <div className="mb-1 flex items-center gap-2">
                  <h4 className="font-semibold">{fund.fund_name}</h4>
                  <Badge variant="outline" className="text-xs">
                    {fund.fund_type}
                  </Badge>
                </div>
                <div className="flex items-center gap-4 text-sm text-gray-600">
                  <span>NAV: ₹{Number(fund.nav).toFixed(2)}</span>
                  <span>AUM: {formatCurrency(Number(fund.aum))}</span>
                  <Badge
                    className={
                      fund.risk_level === "high"
                        ? "bg-red-100 text-red-800"
                        : fund.risk_level === "medium"
                          ? "bg-yellow-100 text-yellow-800"
                          : "bg-green-100 text-green-800"
                    }
                  >
                    {fund.risk_level}
                  </Badge>
                </div>
              </div>
              <Link href={`/manager/funds/${fund.id}`}>
                <Button size="sm" variant="outline" className="gap-2 bg-transparent">
                  <TrendingUp className="h-4 w-4" />
                  Manage
                </Button>
              </Link>
            </div>
          ))}
        </div>

        {managedFunds.length === 0 && <p className="text-center text-gray-500">No funds assigned to you yet.</p>}
      </CardContent>
    </Card>
  )
}
