"use client"

import { useEffect, useState } from "react"
import { useMarketData } from "@/lib/hooks/useMarketData"
import { useAuth } from "@/lib/auth-context"
import { useRouter } from "next/navigation"
import { DashboardHeader } from "@/components/dashboard-header"
import { ManagerOverview } from "@/components/manager/manager-overview"
import { MarketSnapshot } from "@/components/manager/market-snapshot"
import { FundPerformance } from "@/components/manager/fund-performance"
import { OpportunityPanel } from "@/components/manager/opportunity-panel"
import { LocalDB } from "@/lib/local-storage/db"
import { ComparativeChart } from "@/components/manager/comparative-chart"

export default function ManagerDashboard() {
  const { user, loading } = useAuth()
  const router = useRouter()
  const [dataLoading, setDataLoading] = useState(true)
  const [managedFunds, setManagedFunds] = useState<any[]>([])
  const [securities, setSecurities] = useState<any[]>([])
  const { securities: liveSecurities } = useMarketData(2500)

  useEffect(() => {
    if (!loading && !user) {
      router.push("/auth/login")
      return
    }

    if (user && user.role !== "portfolio_manager") {
      router.push("/auth/login")
      return
    }

    if (user) loadData()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, loading])

  const loadData = async () => {
    setDataLoading(true)
    try {
      const funds = await LocalDB.getFunds()
      // For demo mode, assume manager manages funds where manager_id === user.id
      const managed = funds.filter((f: any) => f.manager_id === user?.id || true)
      setManagedFunds(managed)

      // Pull securities from LocalDB (created during initializeDatabase)
      const secs = await LocalDB.getSecurities()
      setSecurities(secs.slice(0, 10))
    } catch (err) {
      console.error(err)
    } finally {
      setDataLoading(false)
    }
  }

  // keep overview securities updated from simulated market data if available
  useEffect(() => {
    if ((liveSecurities || []).length) setSecurities((liveSecurities || []).slice(0, 10))
  }, [liveSecurities])

  const totalAUM = managedFunds.reduce((sum, fund) => sum + Number(fund.aum || 0), 0)

  if (loading || dataLoading || !user) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <div className="text-center">
          <div className="h-8 w-8 animate-spin rounded-full border-4 border-blue-600 border-t-transparent mx-auto mb-4"></div>
          <p className="text-gray-600">Loading dashboard...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <DashboardHeader user={user} />

      <main className="container mx-auto p-6">
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">Portfolio Manager Dashboard</h1>
          <p className="text-gray-600">Manage funds, analyze markets, and execute trades</p>
        </div>

        <div className="grid gap-6 lg:grid-cols-3">
          <div className="lg:col-span-2 space-y-6">
            <ManagerOverview managedFundsCount={managedFunds.length || 0} totalAUM={totalAUM} />
            <FundPerformance managedFunds={managedFunds || []} />
              <div className="mt-6">
                <ComparativeChart />
              </div>
          </div>
          <div className="space-y-6">
            <OpportunityPanel />
            <MarketSnapshot securities={securities || []} />
          </div>
        </div>
      </main>
    </div>
  )
}
